#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>

#define MAXD 20
#define MAXEQ 40

static void mulMat(uint32_t A[MAXD], uint32_t B[MAXD], uint32_t C[MAXD], int d){
    uint32_t colMask[MAXD];
    for(int j=0;j<d;j++){
        uint32_t mask=0;
        for(int i=0;i<d;i++) if((B[i]>>j)&1U) mask|=1U<<i;
        colMask[j]=mask;
    }
    for(int i=0;i<d;i++){
        uint32_t row=0;
        uint32_t a=A[i];
        while(a){
            int l=__builtin_ctz(a);
            row ^= colMask[l];
            a &= a-1;
        }
        C[i]=row;
    }
}

static void matPow(uint32_t base[MAXD], uint64_t exp, uint32_t res[MAXD], int d){
    for(int i=0;i<d;i++) res[i]=1U<<i; // identity
    uint32_t tmp[MAXD];
    while(exp){
        if(exp&1){
            mulMat(res, base, tmp, d);
            for(int i=0;i<d;i++) res[i]=tmp[i];
        }
        mulMat(base, base, tmp, d);
        for(int i=0;i<d;i++) base[i]=tmp[i];
        exp>>=1;
    }
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int d,k; scanf("%d %d",&d,&k);
        uint32_t a[MAXD];
        for(int i=0;i<d;i++){ int bit; scanf("%d",&bit); a[i]=bit; }
        uint32_t M[MAXD];
        for(int i=0;i<d;i++) M[i]=0;
        for(int j=0;j<d;j++) if(a[j]) M[0]|=1U<<j;
        for(int i=1;i<d;i++) M[i]|=1U<<(i-1);
        uint32_t eqMask[MAXEQ];
        uint32_t rhs[MAXEQ];
        int eqCnt=0;
        for(int idx=0; idx<k; idx++){
            unsigned int ij; int xj; scanf("%u %d",&ij,&xj);
            uint32_t Mpow[MAXD];
            uint32_t baseCopy[MAXD];
            for(int i=0;i<d;i++) baseCopy[i]=M[i];
            matPow(baseCopy, ij, Mpow, d);
            eqMask[eqCnt]=Mpow[0];
            rhs[eqCnt]=xj;
            eqCnt++;
        }
        int where[MAXD];
        for(int i=0;i<d;i++) where[i]=-1;
        int row=0;
        for(int col=0; col<d && row<eqCnt; col++){
            int sel=-1;
            for(int i=row;i<eqCnt;i++) if((eqMask[i]>>col)&1U){ sel=i; break; }
            if(sel==-1) continue;
            uint32_t tmpMask=eqMask[row]; eqMask[row]=eqMask[sel]; eqMask[sel]=tmpMask;
            uint32_t tmpRhs=rhs[row]; rhs[row]=rhs[sel]; rhs[sel]=tmpRhs;
            where[col]=row;
            for(int i=0;i<eqCnt;i++) if(i!=row && ((eqMask[i]>>col)&1U)){
                eqMask[i]^=eqMask[row];
                rhs[i]^=rhs[row];
            }
            row++;
        }
        bool noSolution=false;
        for(int i=0;i<eqCnt;i++) if(eqMask[i]==0 && rhs[i]){ noSolution=true; break; }
        if(noSolution){
            printf("no solution
");
            continue;
        }
        if(row<d){
            printf("multiple solutions
");
            continue;
        }
        int sol[MAXD];
        for(int i=0;i<d;i++) sol[i]=0;
        for(int i=0;i<d;i++) if(where[i]!=-1) sol[i]=rhs[where[i]];
        for(int i=0;i<d;i++){
            if(i) printf(" ");
            printf("%d",sol[i]);
        }
        printf("
");
    }
    return 0;
}

